int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b; scanf("%d %d",&a,&b);
        if(((a+b)&1)==0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

